export const IconLockAnimated = ({ isClosed }: { isClosed: boolean }) => {
    return (
        <svg
            xmlns="http://www.w3.org/2000/svg"
            width="24"
            height="24"
            viewBox="0 -1 25 24"
            fill="none"
        >
            <style>
                {`
                    @keyframes hook-bounce {
                        0% {
                            transform:
                                rotate(28deg)
                                translateX(2px)
                                translateY(-1px);
                        }

                        /* FIRST DROP */

                        8% {
                            transform:
                                rotate(6deg)
                                translateX(0px)
                                translateY(0px);
                        }

                        16% {
                            transform:
                                rotate(34deg)
                                translateX(3px)
                                translateY(-1px);
                        }

                        /* SECOND SLOWER DROP */

                        28% {
                            transform:
                                rotate(12deg)
                                translateX(1px)
                                translateY(0px);
                        }

                        40% {
                            transform:
                                rotate(28deg)
                                translateX(2px)
                                translateY(-1px);
                        }

                        /* PAUSE */

                        100% {
                            transform:
                                rotate(28deg)
                                translateX(2px)
                                translateY(-1px);
                        }
                    }
                `}
            </style>

            <g
                style={{
                    transformOrigin: '18px 10px',

                    transform: isClosed
                        ? 'rotate(0deg)'
                        : 'rotate(28deg) translateX(2px) translateY(-1px)',

                    transition: isClosed
                        ? 'transform 0.35s cubic-bezier(0.34, 1.56, 0.64, 1)'
                        : 'none',

                    animation: isClosed
                        ? 'none'
                        :'hook-bounce 2.4s cubic-bezier(0.34, 1.56, 0.64, 1) infinite',
                }}
            >
                <path
                    d="M6 10V8C6 4.69 7 2 12 2C17 2 18 4.69 18 8V10"
                    strokeWidth="1.5"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                />
            </g>

            <path
                d="M17 22H7C3 22 2 21 2 17V15C2 11 3 10 7 10H17C21 10 22 11 22 15V17C22 21 21 22 17 22Z"
                strokeWidth="1.5"
                strokeLinecap="round"
                strokeLinejoin="round"
            />

            <circle
                cx="12"
                cy="16"
                r="1"
                style={{
                    opacity: isClosed ? 1 : 0.45,
                    transition: 'opacity 0.25s ease',
                }}
            />

            <rect
                x="3"
                y="11"
                width="18"
                height="10"
                rx="4"
                opacity={isClosed ? 0 : 0.06}
                style={{
                    transition: 'opacity 0.3s ease',
                }}
            />
        </svg>
    );
};

